# Zenodo metadata callback helpers
DEFAULT_ZENODO_RECORDS_URL = "https://zenodo.org/api/records"
DEFAULT_ZENODO_TIMEOUT = 10.0

class _ZenodoMetadataError(Exception):
    "Raised when Zenodo metadata retrieval fails."
    pass

class _ZenodoMissingRecordError(_ZenodoMetadataError):
    "Raised when the selected Zenodo record does not exist."
    pass

class _ZenodoTransportError(_ZenodoMetadataError):
    "Raised when Zenodo transport fails before a valid payload is received."
    pass

# %% ../nbs/api/metadata.ipynb #c35726a2
def _zenodo_curl_json(url:str,
                      timeout:float=DEFAULT_ZENODO_TIMEOUT # Request timeout in seconds
                     ) -> dict: # Raw Zenodo record payload
    "Fetch a Zenodo record payload via curl."
    try:
        response = subprocess.run(
            [find_curl(), '-sS', '-H', 'Accept: application/json', '-w', r'\n%{http_code}', url],
            capture_output=True, text=True, encoding='utf-8', check=True,
            timeout=max(1, int(timeout * 4)),
        )
    except FileNotFoundError as exc:
        raise _ZenodoTransportError(f'Zenodo metadata retrieval failed: {exc}') from exc
    except subprocess.TimeoutExpired as exc:
        raise _ZenodoTransportError(f'Zenodo metadata retrieval failed: {exc}') from exc
    except subprocess.CalledProcessError as exc:
        raise _ZenodoTransportError(
            'Zenodo metadata retrieval failed: curl returned a non-zero exit code') from exc

    body, _, status_line = response.stdout.rstrip('\n').rpartition('\n')
    try:
        status_code = int(status_line)
    except ValueError as exc:
        raise _ZenodoMetadataError('Zenodo metadata retrieval failed: invalid curl response payload') from exc

    if status_code == 404: raise _ZenodoMissingRecordError('Zenodo metadata retrieval failed: record not found')
    if status_code >= 400: raise _ZenodoMetadataError(f'Zenodo metadata retrieval failed: HTTP {status_code}')

    try:
        return json.loads(body)
    except json.JSONDecodeError as exc:
        raise _ZenodoMetadataError('Zenodo metadata retrieval failed: invalid JSON payload') from exc

# %% ../nbs/api/metadata.ipynb #2efa79db
def _zenodo_fetch_record(
    record_id:str, # Zenodo record identifier
    record_base_url:str=DEFAULT_ZENODO_RECORDS_URL, # API base URL
    timeout:float=DEFAULT_ZENODO_TIMEOUT # Request timeout in seconds
    ) -> dict: # Raw Zenodo record payload
    "Fetch a Zenodo record from the single-record API with curl fallback."
    url = f"{record_base_url.rstrip('/')}/{record_id}"
    try:
        with urlopen(url, timeout=timeout) as response:
            return json.loads(response.read().decode('utf-8'))
    except HTTPError as exc:
        if exc.code == 404: raise _ZenodoMissingRecordError('Zenodo metadata retrieval failed: record not found') from exc
        raise _ZenodoMetadataError(f'Zenodo metadata retrieval failed: HTTP {exc.code}') from exc
    except (URLError, TimeoutError):
        return _zenodo_curl_json(url, timeout=timeout)
    except json.JSONDecodeError as exc:
        raise _ZenodoMetadataError('Zenodo metadata retrieval failed: invalid JSON payload') from exc

# %% ../nbs/api/metadata.ipynb #ce0c4cb3
def _zenodo_as_dict(value): return value if isinstance(value, dict) else {}
def _zenodo_as_list(value): return value if isinstance(value, list) else []
def _zenodo_pick_text(value):
    if isinstance(value, str): return value
    if isinstance(value, dict):
        if value.get('en'): return value.get('en')
        return next((v for v in value.values() if isinstance(v, str) and v), '')
    return '' if value is None else str(value)

# %% ../nbs/api/metadata.ipynb #318ff28a
def _zenodo_metadata(item:dict # Raw Zenodo record payload
                    ) -> dict: # Normalized metadata block
    "Return the normalized Zenodo metadata block."
    return _zenodo_as_dict(_zenodo_as_dict(item).get('metadata'))

def _zenodo_doi(item:dict # Raw Zenodo record payload
               ) -> str: # DOI string, if present
    "Return the preferred DOI string from a Zenodo record."
    metadata = _zenodo_metadata(item)
    doi = _zenodo_pick_text(item.get('doi')) or _zenodo_pick_text(metadata.get('doi'))
    if doi: return doi
    pids = _zenodo_as_dict(item.get('pids'))
    return _zenodo_pick_text(_zenodo_as_dict(pids.get('doi')).get('identifier'))

def _zenodo_url(item:dict # Raw Zenodo record payload
               ) -> str: # Canonical record URL, if present
    "Return the preferred Zenodo record URL."
    links = _zenodo_as_dict(item.get('links'))
    return (_zenodo_pick_text(links.get('self_html'))
            or _zenodo_pick_text(links.get('latest_html'))
            or _zenodo_pick_text(item.get('doi_url')))

# %% ../nbs/api/metadata.ipynb #07210baa
class ZenodoItem:
    "Retrieve Zenodo metadata from the single-record API."
    def __init__(self,
                 record_id:str, # Zenodo record identifier
                 record_base_url:str=DEFAULT_ZENODO_RECORDS_URL, # API base URL
                 timeout:float=DEFAULT_ZENODO_TIMEOUT # Request timeout in seconds
                ) -> None:
        store_attr()
        try: self.item = _zenodo_fetch_record(record_id, record_base_url, timeout)
        except _ZenodoMissingRecordError: self.item = None

    def exist(self) -> bool:
        "Does the selected Zenodo record exist?"
        return self.item is not None and bool(_zenodo_pick_text(_zenodo_as_dict(self.item).get('id')))

    @property
    def title(self) -> str:
        if not self.item: return ''
        return _zenodo_pick_text(_zenodo_metadata(self.item).get('title'))

    @property
    def summary(self) -> str:
        if not self.item: return ''
        return _zenodo_pick_text(_zenodo_metadata(self.item).get('description'))

    @property
    def doi(self) -> str:
        if not self.item: return ''
        return _zenodo_doi(_zenodo_as_dict(self.item))

    @property
    def creator_name(self) -> str:
        if not self.item: return ''
        return json.dumps(_zenodo_as_list(_zenodo_metadata(self.item).get('creators')), ensure_ascii=True)

    @property
    def url(self) -> str:
        if not self.item: return ''
        return _zenodo_url(_zenodo_as_dict(self.item))

    def __repr__(self): return json.dumps(self.item, indent=4)

# %% ../nbs/api/metadata.ipynb #e2f25796
class ZenodoCB(Callback):
    "Populate global attributes from Zenodo metadata."
    def __init__(self,
                 record_id:str, # Zenodo record identifier to retrieve
                 record_base_url:str=DEFAULT_ZENODO_RECORDS_URL, # API base URL
                 timeout:float=DEFAULT_ZENODO_TIMEOUT # Request timeout in seconds
                ): store_attr()
    def __call__(self, obj):
        item = ZenodoItem(self.record_id, self.record_base_url, self.timeout)
        if item.exist():
            obj.attrs['id'] = self.record_id
            for attr in ['title', 'summary', 'creator_name']:
                obj.attrs[attr] = getattr(item, attr)
            if item.doi: obj.attrs['references'] = item.doi
            if item.url: obj.attrs['metadata_link'] = item.url

